data.content:
Use `MockHttpMessageHandler` to control responses, and `CancellationTokenSource` for timeout/cancellation tests:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Helper: create a handler that returns a canned response
    private static HttpClient CreateMockClient(HttpStatusCode status, string content = "")
    {
        var handler = new MockHandler(new HttpResponseMessage(status)
        {
            Content = new StringContent(content)
        });
        return new HttpClient(handler);
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        using var client = CreateMockClient(HttpStatusCode.OK, "hello");
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnHttpError()
    {
        using var client = CreateMockClient(HttpStatusCode.InternalServerError);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // --- Cancellation & timeout tests ---

    [TestMethod]
    public async Task FetchAsync_Throws_WhenAlreadyCancelled()
    {
        using var client = CreateMockClient(HttpStatusCode.OK, "data");
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel before calling

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenCancelledDuringRequest()
    {
        // Handler that waits, giving us time to cancel
        var handler = new DelayHandler(TimeSpan.FromSeconds(30));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // safety net: fail if test hangs
    public async Task FetchAsync_RespectsTimeout()
    {
        var handler = new DelayHandler(TimeSpan.FromSeconds(30));
        using var client = new HttpClient(handler) { Timeout = TimeSpan.FromMilliseconds(50) };
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // --- Test helpers ---

    private class MockHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage _response;
        public MockHandler(HttpResponseMessage response) => _response = response;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken ct)
        {
            ct.ThrowIfCancellationRequested();
            return Task.FromResult(_response);
        }
    }

    private class DelayHandler : HttpMessageHandler
    {
        private readonly TimeSpan _delay;
        public DelayHandler(TimeSpan delay) => _delay = delay;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken ct)
        {
            await Task.Delay(_delay, ct); // throws when cancelled
            return new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key patterns:**

- **`[Timeout(5000)]`** — MSTest-level safety net so a broken test doesn't hang CI forever
- **Pre-cancelled token** — `cts.Cancel()` before the call to test the guard path
- **Mid-flight cancellation** — `CancellationTokenSource(TimeSpan)` with a slow handler to simulate real timeouts
- **`HttpClient.Timeout`** — tests the built-in timeout, which also surfaces as `TaskCanceledException`
- **Custom `HttpMessageHandler`** — avoids real HTTP and gives full control over responses and timing
